ORDINAL_GEN.predicate_code:
if subtask == "ORDINAL_GEN":
    mm = re.search(r"comes immediately (after|before) (\w+)\?", question)
    idx = _ORDINALS.index(mm[2].lower())
    tgt = idx + 1 if mm[1] == "after" else idx - 1
    if not 0 <= tgt < len(_ORDINALS):
        raise ValueError(f"ordinal neighbour out of range: {question}")
    want = _ORDINALS[tgt]
    return lambda o: o.strip().lower() in (want, _ORDINAL_NUM[want])

CAPITAL_GEN.predicate_code:
if subtask == "CAPITAL_GEN":
    c = re.search(r"capital city of ([^?]+)\?", question)[1].strip()
    if c.lower().startswith("the "):
        c = c[4:]
    return lambda o: _CAPITALS[c] == o.strip().lower()

PAST_TENSE_GEN.predicate_code:
if subtask == "PAST_TENSE_GEN":
    v = re.search(r"the verb '(\w+)'\?", question)[1].lower()
    return lambda o: o.lower() == _regular_past(v)
